-- Migration: House predictions — Howard's own synthesized, falsifiable predictions
-- These are generated by synthesizing all source predictions, outlooks, and market data
-- into specific, time-bound, measurable claims that can be scored against reality.

CREATE TABLE IF NOT EXISTS house_predictions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),

  -- The prediction itself
  claim TEXT NOT NULL,                          -- e.g. "S&P 500 will trade below 4800 by June 2026"
  asset TEXT NOT NULL,                          -- e.g. "SPY", "NVDA", "GLD", "BTC-USD"
  direction TEXT NOT NULL CHECK (direction IN ('long', 'short', 'neutral')),

  -- Falsifiability
  target_value NUMERIC,                         -- specific price target if applicable
  target_condition TEXT NOT NULL,               -- e.g. "below 4800", "above 3000", "down >10%", "range 4500-5000"
  reference_value NUMERIC,                      -- price at time of prediction

  -- Time bounds
  time_horizon TEXT NOT NULL,                   -- e.g. "30 days", "3 months", "6 months"
  deadline TIMESTAMPTZ NOT NULL,               -- hard deadline for evaluation

  -- Confidence & reasoning
  confidence NUMERIC NOT NULL CHECK (confidence >= 0 AND confidence <= 100),  -- 0-100%
  conviction TEXT NOT NULL CHECK (conviction IN ('high', 'medium', 'low')),
  thesis TEXT NOT NULL,                         -- why Howard believes this
  supporting_sources TEXT[],                    -- which sources informed this view
  key_drivers TEXT[],                           -- what factors would make this true
  invalidation_criteria TEXT,                   -- what would prove this wrong early

  -- Categorization
  category TEXT NOT NULL DEFAULT 'macro',       -- macro, sector, single-stock, rates, commodities, crypto
  themes TEXT[] DEFAULT '{}',

  -- Outcome tracking
  outcome TEXT CHECK (outcome IN ('correct', 'incorrect', 'partially_correct', 'expired', 'invalidated', 'pending')),
  outcome_score NUMERIC CHECK (outcome_score >= 0 AND outcome_score <= 1),
  outcome_reasoning TEXT,
  final_value NUMERIC,                          -- actual price at evaluation time
  evaluated_at TIMESTAMPTZ,

  -- Versioning — tracks how the house view evolved
  superseded_by UUID REFERENCES house_predictions(id),
  supersedes UUID REFERENCES house_predictions(id),
  version INTEGER DEFAULT 1,

  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Calibration tracking — measures whether confidence levels are well-calibrated
-- e.g. do 70% confidence predictions actually come true ~70% of the time?
CREATE TABLE IF NOT EXISTS house_calibration (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  confidence_bucket INTEGER NOT NULL,           -- 10, 20, 30, ..., 90 (bucket center)
  total_predictions INTEGER NOT NULL DEFAULT 0,
  correct_predictions INTEGER NOT NULL DEFAULT 0,
  actual_rate NUMERIC DEFAULT 0,                -- actual success rate in this bucket
  calibration_error NUMERIC DEFAULT 0,          -- |actual_rate - expected_rate|
  category TEXT DEFAULT 'all',                  -- can be per-category or 'all'
  computed_at TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE(confidence_bucket, category)
);

-- Snapshot of Howard's overall predictive track record over time
CREATE TABLE IF NOT EXISTS house_track_record (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  total_predictions INTEGER NOT NULL DEFAULT 0,
  evaluated INTEGER NOT NULL DEFAULT 0,
  correct INTEGER NOT NULL DEFAULT 0,
  partially_correct INTEGER NOT NULL DEFAULT 0,
  incorrect INTEGER NOT NULL DEFAULT 0,
  overall_accuracy NUMERIC DEFAULT 0,
  weighted_accuracy NUMERIC DEFAULT 0,          -- weighted by confidence
  brier_score NUMERIC DEFAULT 0,               -- calibration metric (lower = better)
  avg_confidence NUMERIC DEFAULT 0,
  best_category TEXT,
  worst_category TEXT,
  active_predictions INTEGER DEFAULT 0,
  computed_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_house_predictions_outcome ON house_predictions(outcome);
CREATE INDEX IF NOT EXISTS idx_house_predictions_deadline ON house_predictions(deadline);
CREATE INDEX IF NOT EXISTS idx_house_predictions_asset ON house_predictions(asset);
CREATE INDEX IF NOT EXISTS idx_house_predictions_category ON house_predictions(category);
